 1→import React from 'react';
 2→import { motion, AnimatePresence } from 'framer-motion';
 3→import { REACTION_TYPES } from '../../utils/reactionConfig';
 4→import './reactions.css';
 5→
 6→const ReactionPicker = ({ isOpen, onSelect, currentReaction }) => {
 7→    const isMobile = typeof window !== 'undefined' && window.innerWidth <= 480;
 8→    const xOffset = isMobile ? 0 : '-50%';
 9→
10→    return (
11→        <AnimatePresence>
12→            {isOpen && (
13→                <motion.div
14→                    className="reaction-picker"
15→                    initial={{ opacity: 0, scale: 0.8, y: 8, x: xOffset }}
16→                    animate={{ opacity: 1, scale: 1, y: 0, x: xOffset }}
17→                    exit={{ opacity: 0, scale: 0.8, y: 8, x: xOffset }}
18→                    transition={{ type: 'spring', damping: 20, stiffness: 400 }}
19→                >
20→                    {REACTION_TYPES.map((reaction, index) => (
21→                        <motion.button
22→                            key={reaction.type}
23→                            className={`reaction-picker-item ${currentReaction === reaction.type ? 'is-active' : ''}`}
24→                            onClick={(e) => {
25→                                e.preventDefault();
26→                                e.stopPropagation();
27→                                onSelect(reaction.type);
28→                            }}
29→                            title={reaction.label}
30→                            initial={{ opacity: 0, y: 10 }}
31→                            animate={{ opacity: 1, y: 0 }}
32→                            transition={{ delay: index * 0.03 }}
33→                            whileHover={{ scale: 1.4 }}
34→                            whileTap={{ scale: 0.9 }}
35→                        >
36→                            {reaction.emoji}
37→                        </motion.button>
38→                    ))}
39→                </motion.div>
40→            )}
41→        </AnimatePresence>
42→    );
43→};
44→
45→export default ReactionPicker;
