 1→import React from 'react';
 2→import { useQuery } from '@tanstack/react-query';
 3→import { getPostReactions } from '../../../API/Api';
 4→import { getReactionEmoji } from '../../utils/reactionConfig';
 5→import './reactions.css';
 6→
 7→const ReactionSummary = ({ journalId }) => {
 8→    const { data } = useQuery({
 9→        queryKey: ['postReactions', journalId],
10→        queryFn: () => getPostReactions(journalId),
11→        enabled: !!journalId,
12→        staleTime: 1000 * 60 * 2,
13→        refetchOnWindowFocus: false,
14→    });
15→
16→    const reactions = data?.reactions || [];
17→
18→    if (reactions.length === 0) return null;
19→
20→    return (
21→        <div className="reaction-summary">
22→            {reactions.map((group) => (
23→                <span key={group.reaction_type} className="reaction-summary-chip">
24→                    <span className="reaction-summary-emoji">{getReactionEmoji(group.reaction_type)}</span>
25→                    <span className="reaction-summary-count">{group.count}</span>
26→                </span>
27→            ))}
28→        </div>
29→    );
30→};
31→
32→export default ReactionSummary;
